import { data, takaro } from '@takaro/helpers';
async function main() {
    const { player, pog, gameServerId } = data;
    // The log message is provided by the Takaro event data.
    const logMessageFromTakaro = data.eventData.msg;

    // The regex to find and capture the CrossId.
    const match = logMessageFromTakaro.match(/CrossId='(EOS_.*?)'/);

    // Directly access the captured ID, since a match is guaranteed.
    const eosID = match[1];

    console.log(`Found EOS ID: ${eosID}`);


    //eoc <Name/EntityId/SteamId> "command param1 param2"
    //getdrone ${eosID}
    await takaro.gameserver.gameServerControllerExecuteCommand(data.gameServerId, {
        command: `getdrone ${eosID}`,
    });

}
await main();
